#!/bin/bash
whois $1 | awk -F': ' 'BEGIN{s="Registrant,Admin,Tech";f="Name,Organization,Street,City,State/Province,Postal Code,Country,Phone,Phone Ext:,Fax,Fax Ext:,Email";split(s,S,",");split(f,F,",")} {gsub(/^[ \t]+|[ \t]+$/, "", $1); gsub(/^[ \t]+|[ \t]+$/, $2); if($1!="" && $2!="") d[tolower($1)]=$2} END{for(i=1;i<=3;i++) for(j=1;j<=12;j++){k=tolower(S[i]" "F[j]); gsub(/state\/province/,"state",k); gsub(/postal code/,"postal code",k); gsub(/phone ext:/,"phone ext",k); gsub(/fax ext:/,"fax ext",k); v=d[k]; if(F[j]=="Street" && v!="") v=v" "; printf "%s%s,%s\n", S[i], (F[j]~/Ext:/?"":"") F[j], v}}' > $1.csv
